import pytest
import requests

def test_create_observation_with_loinc_code_returns_201(
    clinician_auth_headers,  # <fixture>
    existing_patient_id,     # <fixture>
    fhir_base_url,           # <fixture>
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "8310-5",
                "display": "Body temperature"
            }]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    obs_id = None
    try:
        r = requests.post(
            f"{fhir_base_url}/Observation",
            json=payload,
            headers=clinician_auth_headers,
        )
        assert r.status_code == 201, r.text
        body = r.json()
        obs_id = body.get("id")
        assert obs_id, "Response must include an id"
        assert body["resourceType"] == "Observation"
        assert body["code"]["coding"][0]["system"] == "http://loinc.org"
        assert body["code"]["coding"][0]["code"] == "8310-5"
    finally:
        if obs_id:
            requests.delete(
                f"{fhir_base_url}/Observation/{obs_id}",
                headers=clinician_auth_headers,
            )

import pytest
import requests

def test_create_observation_with_empty_coding_array_returns_422(
    clinician_auth_headers,  # <fixture>
    existing_patient_id,     # <fixture>
    fhir_base_url,           # <fixture>
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {"coding": []},  # boundary: present but zero codings
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    r = requests.post(
        f"{fhir_base_url}/Observation",
        json=payload,
        headers=clinician_auth_headers,
    )
    assert r.status_code == 422, (
        f"Expected 422 for empty coding array but got {r.status_code}: {r.text}"
    )
    body = r.json()
    issue_text = str(body).lower()
    assert "cod" in issue_text or "loinc" in issue_text or "validation" in issue_text, (
        f"Error body does not reference coding: {body}"
    )

import pytest
import requests

def test_audit_event_emitted_for_successful_observation_creation(
    clinician_auth_headers,  # <fixture>
    existing_patient_id,     # <fixture>
    fhir_base_url,           # <fixture>
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "8310-5"
            }]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    obs_id = None
    try:
        r = requests.post(
            f"{fhir_base_url}/Observation",
            json=payload,
            headers=clinician_auth_headers,
        )
        assert r.status_code == 201, r.text
        obs_id = r.json()["id"]
        audit_r = requests.get(
            f"{fhir_base_url}/AuditEvent",
            params={"entity": f"Observation/{obs_id}"},
            headers=clinician_auth_headers,
        )
        assert audit_r.status_code == 200, audit_r.text
        bundle = audit_r.json()
        entries = bundle.get("entry", [])
        assert len(entries) >= 1, (
            f"Expected AuditEvent for Observation/{obs_id}, got none"
        )
        ref_strs = str(entries).lower()
        assert obs_id.lower() in ref_strs, "AuditEvent does not reference Observation id"
    finally:
        if obs_id:
            requests.delete(
                f"{fhir_base_url}/Observation/{obs_id}",
                headers=clinician_auth_headers,
            )

import pytest
import requests

def test_observation_state_transition_draft_to_final(
    clinician_auth_headers,  # <fixture>
    existing_patient_id,     # <fixture>
    fhir_base_url,           # <fixture>
):
    base_payload = {
        "resourceType": "Observation",
        "status": "preliminary",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "8310-5"
            }]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    obs_id = None
    try:
        r1 = requests.post(
            f"{fhir_base_url}/Observation",
            json=base_payload,
            headers=clinician_auth_headers,
        )
        assert r1.status_code == 201, r1.text
        body1 = r1.json()
        obs_id = body1["id"]
        assert body1["status"] == "preliminary"
        update_payload = {**base_payload, "id": obs_id, "status": "final"}
        r2 = requests.put(
            f"{fhir_base_url}/Observation/{obs_id}",
            json=update_payload,
            headers=clinician_auth_headers,
        )
        assert r2.status_code == 200, r2.text
        assert r2.json()["status"] == "final"
        audit_r = requests.get(
            f"{fhir_base_url}/AuditEvent",
            params={"entity": f"Observation/{obs_id}", "action": "U"},
            headers=clinician_auth_headers,
        )
        assert len(audit_r.json().get("entry", [])) >= 1
    finally:
        if obs_id:
            requests.delete(
                f"{fhir_base_url}/Observation/{obs_id}",
                headers=clinician_auth_headers,
            )
